import{_ as d,o as e,c as a,a2 as o}from"./chunks/framework._O8Cueap.js";const b=JSON.parse('{"title":"API Endpoints","description":"","frontmatter":{},"headers":[],"relativePath":"reference/api-endpoints.md","filePath":"reference/api-endpoints.md"}'),r={name:"reference/api-endpoints.md"};function i(s,t,c,n,h,l){return e(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="api-endpoints" tabindex="-1">API Endpoints <a class="header-anchor" href="#api-endpoints" aria-label="Permalink to &quot;API Endpoints&quot;">​</a></h1><p>All routes are served by OAO-API (Hono v4.6) at port 4002. OAO-UI proxies all <code>/api/*</code> requests to the API.</p><p><strong>Authentication</strong>: JWT tokens signed with HS256, 7-day expiry, or Personal Access Tokens (PAT). Include in headers: <code>Authorization: Bearer &lt;token&gt;</code></p><p>PATs use <code>oao_</code> prefix (e.g., <code>Authorization: Bearer oao_abc123...</code>). PATs have fine-grained scopes controlling access.</p><h2 id="authentication" tabindex="-1">Authentication <a class="header-anchor" href="#authentication" aria-label="Permalink to &quot;Authentication&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Method</th><th>Path</th><th>Auth</th><th>Description</th></tr></thead><tbody><tr><td>POST</td><td><code>/api/auth/register</code></td><td>No</td><td>Register new user (optional <code>workspaceSlug</code>, defaults to <code>default</code>)</td></tr><tr><td>POST</td><td><code>/api/auth/login</code></td><td>No</td><td>Login with <code>email</code>, <code>password</code>, optional <code>provider</code> (<code>database</code>/<code>ldap</code>). Returns JWT</td></tr><tr><td>GET</td><td><code>/api/auth/me</code></td><td>JWT</td><td>Current user info + workspace</td></tr><tr><td>PUT</td><td><code>/api/auth/change-password</code></td><td>JWT</td><td>Change password (database users only, LDAP users get 400)</td></tr><tr><td>GET</td><td><code>/api/auth/providers</code></td><td>No</td><td>List enabled auth providers for a workspace (query: <code>?workspace=slug</code>)</td></tr></tbody></table><h2 id="auth-providers-admin" tabindex="-1">Auth Providers (Admin) <a class="header-anchor" href="#auth-providers-admin" aria-label="Permalink to &quot;Auth Providers (Admin)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Method</th><th>Path</th><th>Role</th><th>Description</th></tr></thead><tbody><tr><td>GET</td><td><code>/api/auth-providers</code></td><td>admin</td><td>List auth providers for current workspace</td></tr><tr><td>POST</td><td><code>/api/auth-providers</code></td><td>admin</td><td>Create auth provider (type, name, config)</td></tr><tr><td>GET</td><td><code>/api/auth-providers/:id</code></td><td>admin</td><td>Get single auth provider (sensitive fields redacted)</td></tr><tr><td>PUT</td><td><code>/api/auth-providers/:id</code></td><td>admin</td><td>Update auth provider (config is merged, not replaced)</td></tr><tr><td>DELETE</td><td><code>/api/auth-providers/:id</code></td><td>admin</td><td>Delete auth provider</td></tr><tr><td>POST</td><td><code>/api/auth-providers/test-connection</code></td><td>admin</td><td>Test LDAP connection (dry-run bind + search)</td></tr></tbody></table><h2 id="agents" tabindex="-1">Agents <a class="header-anchor" href="#agents" aria-label="Permalink to &quot;Agents&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Method</th><th>Path</th><th>Role</th><th>Description</th></tr></thead><tbody><tr><td>GET</td><td><code>/api/agents</code></td><td>Any</td><td>List agents in workspace</td></tr><tr><td>POST</td><td><code>/api/agents</code></td><td>creator+</td><td>Create agent</td></tr><tr><td>GET</td><td><code>/api/agents/:id</code></td><td>Any</td><td>Agent detail (workspace-scoped)</td></tr><tr><td>PUT</td><td><code>/api/agents/:id</code></td><td>creator+</td><td>Update agent</td></tr><tr><td>DELETE</td><td><code>/api/agents/:id</code></td><td>creator+</td><td>Delete agent</td></tr></tbody></table><h2 id="workflows" tabindex="-1">Workflows <a class="header-anchor" href="#workflows" aria-label="Permalink to &quot;Workflows&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Method</th><th>Path</th><th>Role</th><th>Description</th></tr></thead><tbody><tr><td>GET</td><td><code>/api/workflows</code></td><td>Any</td><td>List workflows in workspace. Query: <code>?labels=a,b</code> filters by labels (AND logic)</td></tr><tr><td>GET</td><td><code>/api/workflows/labels</code></td><td>Any</td><td>List all distinct labels in workspace</td></tr><tr><td>POST</td><td><code>/api/workflows</code></td><td>creator+</td><td>Create workflow with steps + triggers</td></tr><tr><td>GET</td><td><code>/api/workflows/:id</code></td><td>Any</td><td>Workflow detail with steps</td></tr><tr><td>PUT</td><td><code>/api/workflows/:id</code></td><td>creator+</td><td>Update workflow (name, description, labels, defaults)</td></tr><tr><td>DELETE</td><td><code>/api/workflows/:id</code></td><td>creator+</td><td>Delete workflow</td></tr><tr><td>POST</td><td><code>/api/workflows/:id/run</code></td><td>creator+</td><td>Manual run — validates inputs against webhook trigger parameters, enqueues execution directly</td></tr></tbody></table><h2 id="executions" tabindex="-1">Executions <a class="header-anchor" href="#executions" aria-label="Permalink to &quot;Executions&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Method</th><th>Path</th><th>Description</th></tr></thead><tbody><tr><td>GET</td><td><code>/api/executions</code></td><td>List executions (paginated)</td></tr><tr><td>GET</td><td><code>/api/executions/active</code></td><td>Check for active executions for a workflow</td></tr><tr><td>GET</td><td><code>/api/executions/:id</code></td><td>Execution detail with step results</td></tr><tr><td>GET</td><td><code>/api/executions/:id/steps/:stepId/live</code></td><td>Live intermediate output for a running step</td></tr><tr><td>POST</td><td><code>/api/executions/:id/cancel</code></td><td>Cancel running execution</td></tr><tr><td>POST</td><td><code>/api/executions/:id/retry</code></td><td>Retry from failed step</td></tr></tbody></table><h2 id="variables" tabindex="-1">Variables <a class="header-anchor" href="#variables" aria-label="Permalink to &quot;Variables&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Method</th><th>Path</th><th>Description</th></tr></thead><tbody><tr><td>GET</td><td><code>/api/variables?scope=user</code></td><td>List user variables</td></tr><tr><td>GET</td><td><code>/api/variables?scope=workspace</code></td><td>List workspace variables</td></tr><tr><td>GET</td><td><code>/api/variables?agentId=...</code></td><td>List agent variables</td></tr><tr><td>POST</td><td><code>/api/variables</code></td><td>Create variable (body.scope: agent/user/workspace)</td></tr><tr><td>PUT</td><td><code>/api/variables/:id</code></td><td>Update variable</td></tr><tr><td>DELETE</td><td><code>/api/variables/:id?scope=...</code></td><td>Delete variable</td></tr></tbody></table><h2 id="triggers" tabindex="-1">Triggers <a class="header-anchor" href="#triggers" aria-label="Permalink to &quot;Triggers&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Method</th><th>Path</th><th>Description</th></tr></thead><tbody><tr><td>GET</td><td><code>/api/triggers?workflowId=...</code></td><td>List triggers for workflow</td></tr><tr><td>POST</td><td><code>/api/triggers</code></td><td>Create trigger</td></tr><tr><td>PUT</td><td><code>/api/triggers/:id</code></td><td>Update trigger</td></tr><tr><td>DELETE</td><td><code>/api/triggers/:id</code></td><td>Delete trigger</td></tr></tbody></table><h2 id="agent-files" tabindex="-1">Agent Files <a class="header-anchor" href="#agent-files" aria-label="Permalink to &quot;Agent Files&quot;">​</a></h2><p>For agents with <code>sourceType: database</code>:</p><table tabindex="0"><thead><tr><th>Method</th><th>Path</th><th>Role</th><th>Description</th></tr></thead><tbody><tr><td>GET</td><td><code>/api/agent-files/:agentId</code></td><td>Any</td><td>List files for agent</td></tr><tr><td>POST</td><td><code>/api/agent-files/:agentId</code></td><td>creator+</td><td>Create file</td></tr><tr><td>PUT</td><td><code>/api/agent-files/:agentId/:fileId</code></td><td>creator+</td><td>Update file content</td></tr><tr><td>DELETE</td><td><code>/api/agent-files/:agentId/:fileId</code></td><td>creator+</td><td>Delete file</td></tr></tbody></table><h2 id="system-events" tabindex="-1">System Events <a class="header-anchor" href="#system-events" aria-label="Permalink to &quot;System Events&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Method</th><th>Path</th><th>Description</th></tr></thead><tbody><tr><td>GET</td><td><code>/api/events</code></td><td>List system events (paginated)</td></tr><tr><td>GET</td><td><code>/api/events/names</code></td><td>Available event names</td></tr></tbody></table><h2 id="admin" tabindex="-1">Admin <a class="header-anchor" href="#admin" aria-label="Permalink to &quot;Admin&quot;">​</a></h2><p>Requires <code>workspace_admin</code> or <code>super_admin</code> role.</p><table tabindex="0"><thead><tr><th>Method</th><th>Path</th><th>Description</th></tr></thead><tbody><tr><td>GET</td><td><code>/api/admin/users</code></td><td>List workspace users</td></tr><tr><td>PUT</td><td><code>/api/admin/users/:id/role</code></td><td>Change user role</td></tr><tr><td>GET/POST/PUT/DELETE</td><td><code>/api/admin/models[/:id]</code></td><td>Model CRUD (workspace-scoped)</td></tr><tr><td>GET/PUT</td><td><code>/api/admin/quota</code></td><td>Workspace rate limit settings</td></tr><tr><td>GET</td><td><code>/api/admin/usage/summary</code></td><td>Workspace credit usage breakdown</td></tr></tbody></table><h2 id="rate-limits" tabindex="-1">Rate Limits <a class="header-anchor" href="#rate-limits" aria-label="Permalink to &quot;Rate Limits&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Method</th><th>Path</th><th>Description</th></tr></thead><tbody><tr><td>GET</td><td><code>/api/quota/models</code></td><td>Active models (for dropdowns)</td></tr><tr><td>GET/PUT</td><td><code>/api/quota/settings</code></td><td>User rate limit settings</td></tr><tr><td>GET</td><td><code>/api/quota/usage</code></td><td>Credit usage stats (daily/weekly/monthly + model breakdown)</td></tr></tbody></table><h2 id="workspaces" tabindex="-1">Workspaces <a class="header-anchor" href="#workspaces" aria-label="Permalink to &quot;Workspaces&quot;">​</a></h2><p>Requires <code>super_admin</code> role.</p><table tabindex="0"><thead><tr><th>Method</th><th>Path</th><th>Description</th></tr></thead><tbody><tr><td>GET</td><td><code>/api/workspaces</code></td><td>List all workspaces</td></tr><tr><td>POST</td><td><code>/api/workspaces</code></td><td>Create workspace</td></tr><tr><td>GET</td><td><code>/api/workspaces/:id</code></td><td>Workspace detail + members</td></tr><tr><td>PUT</td><td><code>/api/workspaces/:id</code></td><td>Update workspace</td></tr><tr><td>DELETE</td><td><code>/api/workspaces/:id</code></td><td>Delete (non-default, 0 members only)</td></tr><tr><td>PUT</td><td><code>/api/workspaces/:id/members/:userId</code></td><td>Move user + set role</td></tr></tbody></table><h2 id="personal-access-tokens" tabindex="-1">Personal Access Tokens <a class="header-anchor" href="#personal-access-tokens" aria-label="Permalink to &quot;Personal Access Tokens&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Method</th><th>Path</th><th>Auth</th><th>Description</th></tr></thead><tbody><tr><td>GET</td><td><code>/api/tokens/scopes</code></td><td>JWT</td><td>List available PAT scopes</td></tr><tr><td>POST</td><td><code>/api/tokens</code></td><td>JWT</td><td>Create PAT (returns raw token once)</td></tr><tr><td>GET</td><td><code>/api/tokens</code></td><td>JWT</td><td>List user&#39;s PATs</td></tr><tr><td>DELETE</td><td><code>/api/tokens/:id</code></td><td>JWT</td><td>Revoke PAT</td></tr></tbody></table><h2 id="webhooks" tabindex="-1">Webhooks <a class="header-anchor" href="#webhooks" aria-label="Permalink to &quot;Webhooks&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Method</th><th>Path</th><th>Auth</th><th>Description</th></tr></thead><tbody><tr><td>POST</td><td><code>/api/webhooks/:path</code></td><td>HMAC-SHA256 or PAT (<code>webhook:trigger</code>)</td><td>Receive webhook events. Validates parameters defined on the trigger.</td></tr></tbody></table><h2 id="supervisor" tabindex="-1">Supervisor <a class="header-anchor" href="#supervisor" aria-label="Permalink to &quot;Supervisor&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Method</th><th>Path</th><th>Role</th><th>Description</th></tr></thead><tbody><tr><td>POST</td><td><code>/api/supervisor/emergency-stop</code></td><td>admin</td><td>Pause all active agents</td></tr><tr><td>POST</td><td><code>/api/supervisor/resume-all</code></td><td>admin</td><td>Resume all paused agents</td></tr><tr><td>GET</td><td><code>/api/supervisor/status</code></td><td>admin</td><td>System-wide supervisor status</td></tr></tbody></table>',37)])])}const u=d(r,[["render",i]]);export{b as __pageData,u as default};
